var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"......이 정도면 주변에 얼씬거리는 것들은 다 치운 것 같군.","JPN":"……これくらいなら、周りにうろついてるのは全部片付いたようだ。","ENG":"That should have taken care of most of the C.O.s around here.","TWN":"……這樣的話，殺來附近的東西差不多都除掉了。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"가, 감사합니다!","JPN":"あ、ありがとうございます！","ENG":"Th-thank you!","TWN":"非、非常謝謝妳！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"근처에 카운터가 계셔서 다행이에요!","JPN":"近くにカウンターがいてよかったです！","ENG":"Thank God, we've got a Counter in the midst of us!","TWN":"有制裁者在附近真是太好了！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"괜찮아. 이제 안전해. 당신도 그만 가보라고.","JPN":"大丈夫、もう安全だ。お前も帰っていいぞ。","ENG":"You're welcome. Everything's okay now. You can go.","TWN":"放心，現在安全了，你也快走吧。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"그래서야 은인에 대한 예의가 아니죠. 답례로 저녁만찬은 어떠신가요?","JPN":"このまま帰ったら恩人に対して失礼です。お礼にディナーはいかがですか？","ENG":"But I'd like to repay you. How about I treat you to dinner tonight?","TWN":"這樣不是對待恩人該有的禮儀，作為謝禮，我請妳吃頓晚餐如何？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"괘, 괜찮은데.","JPN":"べ、別にいらない。","ENG":"Th-that wouldn't be necessary.","TWN":"不、不用了。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"혹시 혼자 오셨나요? 오늘 선상파티가 있을 예정인데 같이 동행하시죠!","JPN":"もしかして、一人で来られたのですか？\\n今日、船上パーティーが行われる予定ですが、一緒にどうですか？","ENG":"Are you here alone? There will be a cruise party tonight. How'd you like to come with me?","TWN":"妳是一個人來的嗎？今天我們預定要舉辦船上派對，妳也一起參加吧！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"응? 그거 VIP만 참석할 수 있는 행사 아닌가? 난 그런 거 없는데......","JPN":"うん？　それはVIPしか参加できないパーティーじゃないのか？　私はVIPじゃないのだが……","ENG":"Huh? I thought that was for VIPs only. I'm not a VIP.","TWN":"咦？那個不是只有VIP才能參加的活動嗎？我不是VIP啊……"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"난 우리 동사무소 단체 워크숍 사전 답사로 온 거라......","JPN":"私は役所のワークショップの下見で来ただけで……","ENG":"I came here location-scouting for the city hall's next workshop...","TWN":"我是為了我們區公所旅遊團先來這裡踩點的……"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VISITOR_NPC_SUMMER_NULL","text":{"KOREA":"괜찮습니다, VIP들은 파트너를 데려갈 수 있거든요. 당신이 함께 있어준다면 파티가 훨씬 빛날 겁니다!","JPN":"大丈夫です。VIPはパートナーを連れていくことができますから。\\nあなたが一緒にいてくれれば、パーティーがもっと輝くはずです！","ENG":"Don't worry. VIPs can bring partners with them. Please come with me and grace the party with your presence!","TWN":"沒關係，VIP可以帶同伴一起參加。如果妳能夠參加，一定可以讓派對更添光彩的！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"그, 그래도 갑자기 그런 걸 권하면 곤란하달까......","JPN":"だ、だが急に誘われて困るというか……","ENG":"B-but this is all too sudden...","TWN":"不、不過這有點太突然了，我有點困擾……"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"와아, 저 언니. 엄청난 실력의 카운터였네요.","JPN":"わぁ、あのお姉さん。すごい腕前のカウンターだったんですね。","ENG":"Wow, that lady. She is an incredible Counter!","TWN":"哇，那個姐姐原來是一個超強的制裁者呢。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"후훗, 이러면 저흰 나설 필요도 없었겠는데요?","JPN":"ふふっ、私たちが出るまでもなかったんですね。","ENG":"Hah hah. We didn't even have to step in.","TWN":"呵呵，這樣就不需要我們出手了吧？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저, 저 사람 방금 뭐였죠? 검을 휘두르는 것도 안 보였는데, 침식체들이 순식간에......","JPN":"あ、あの人は何なんですか？　剣を振るうところが見えなかったんですが、あっという間に侵食体が……","ENG":"W-what did she do? I didn't even see her swinging her sword, and the C.O.s instantly dropped like fallen leaves.","TWN":"那個人剛才做了什麼？也沒看到她揮刀，侵蝕體瞬間就倒地了……"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"흐음~ 인기가 많은 여자라더니, 저 녀석이 네가 말한 다음 운명의 고리인가 보군.","JPN":"ふう～ん、モテる女だそうだが、あいつが其方の言ってた次の運命の相手みたいじゃ。","ENG":"Hm, a popular woman, huh? She must be the next link of your destiny.","TWN":"嗯～確實是個受歡迎的女性，看來她就是妳說的下一個命運之環了。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"특히 저 눈...... 제법 흥미로운데?","JPN":"特にあの目……なかなか面白いのう。","ENG":"And that eye... It's pretty interesting.","TWN":"尤其是那隻眼睛……好像很有趣嘛？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};